     1→/**
     2→ * MicroLayer - Detailed task card visualization
     3→ *
     4→ * Renders detailed task cards with labels at zoom > 2.0x (MICRO LOD level).
     5→ *
     6→ * PERFORMANCE OPTIMIZATIONS:
     7→ * - Frustum culling: Only renders tasks visible in the viewport
     8→ * - InstancedMesh for grid lines: Single draw call instead of ~251 meshes
     9→ * - Lazy label rendering: Only labels for visible tasks
    10→ * - InstancedMesh for row backgrounds: Single draw call instead of 50 meshes
    11→ */
    12→
    13→import { useMemo, useRef, useEffect } from 'react';
    14→import { InstancedMesh, Object3D, Color } from 'three';
    15→import { Html } from '@react-three/drei';
    16→import { useThree } from '@react-three/fiber';
    17→import type { TaskRender } from '../../data/types';
    18→import { DEFAULT_VIEW_CONFIG } from '../../data/types';
    19→import type { ViewportBounds } from '../InfiniteCanvas';
    20→
    21→interface MicroLayerProps {
    22→  tasks: TaskRender[];
    23→  trainCount: number;
    24→  /** Opacity for LOD transitions (0-1). Default: 1 */
    25→  opacity?: number;
    26→  /** Viewport bounds for frustum culling */
    27→  viewportBounds?: ViewportBounds;
    28→  /** Currently hovered task ID for highlight effect */
    29→  hoveredTaskId?: string | null;
    30→  /** Currently selected task ID for selection highlight (F019) */
    31→  selectedTaskId?: string | null;
    32→}
    33→
    34→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
    35→
    36→// Task card dimensions
    37→const CARD_PADDING = 2;
    38→const CARD_HEIGHT = pxPerTrain - CARD_PADDING * 2 - 2; // Slightly smaller for grid visibility
    39→
    40→// Color mappings (matching MesoLayer)
    41→const COLORS: Record<string, string> = {
    42→  blue: '#3b82f6',
    43→  orange: '#f59e0b',
    44→  gray: '#9ca3af',
    45→};
    46→const CONFLICT_COLOR = '#ef4444';
    47→
    48→// Grid colors
    49→const GRID_COLOR_MAJOR = '#d1d5db'; // Gray-300
    50→const GRID_COLOR_MINOR = '#e5e7eb'; // Gray-200
    51→
    52→// Row background colors
    53→const ROW_BG_EVEN = '#ffffff';
    54→const ROW_BG_ODD = '#f8fafc';
    55→
    56→/**
    57→ * Filter tasks that are visible within the viewport bounds
    58→ * This is the core of frustum culling for performance
    59→ */
    60→function filterVisibleTasks(tasks: TaskRender[], viewportBounds?: ViewportBounds): TaskRender[] {
    61→  if (!viewportBounds) return tasks;
    62→
    63→  // Add padding to viewport bounds (render slightly outside visible area for smooth panning)
    64→  const padding = 100; // world units
    65→  const minX = viewportBounds.minX - padding;
    66→  const maxX = viewportBounds.maxX + padding;
    67→  const minY = viewportBounds.minY - padding;
    68→  const maxY = viewportBounds.maxY + padding;
    69→
    70→  return tasks.filter((task) => {
    71→    const taskStartX = task.startDay * pxPerDay;
    72→    const taskEndX = taskStartX + task.duration * pxPerDay;
    73→    const taskY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
    74→
    75→    // Check if task overlaps with viewport
    76→    const xOverlap = taskEndX >= minX && taskStartX <= maxX;
    77→    const yOverlap = taskY + pxPerTrain / 2 >= minY && taskY - pxPerTrain / 2 <= maxY;
    78→
    79→    return xOverlap && yOverlap;
    80→  });
    81→}
    82→
    83→// Highlight color multiplier for hovered tasks
    84→const HOVER_BRIGHTNESS = 1.3;
    85→
    86→// Selection indicator color (distinct cyan/teal)
    87→const SELECTION_COLOR = '#06b6d4'; // cyan-500
    88→
    89→/**
    90→ * Brighten a color for hover effect
    91→ */
    92→function brightenColor(hexColor: string, factor: number): Color {
    93→  const color = new Color(hexColor);
    94→  color.r = Math.min(1, color.r * factor);
    95→  color.g = Math.min(1, color.g * factor);
    96→  color.b = Math.min(1, color.b * factor);
    97→  return color;
    98→}
    99→
   100→/**
   101→ * Task cards using InstancedMesh (same pattern as MesoLayer)
   102→ */
   103→function TaskCards({
   104→  tasks,
   105→  opacity = 1,
   106→  hoveredTaskId,
   107→  selectedTaskId,
   108→}: {
   109→  tasks: TaskRender[];
   110→  opacity?: number;
   111→  hoveredTaskId?: string | null;
   112→  selectedTaskId?: string | null;
   113→}) {
   114→  const meshRef = useRef<InstancedMesh>(null);
   115→  const tempObject = useMemo(() => new Object3D(), []);
   116→  const tempColor = useMemo(() => new Color(), []);
   117→
   118→  useEffect(() => {
   119→    if (!meshRef.current || tasks.length === 0) return;
   120→
   121→    const mesh = meshRef.current;
   122→
   123→    tasks.forEach((task, i) => {
   124→      const width = task.duration * pxPerDay - CARD_PADDING * 2;
   125→      const height = CARD_HEIGHT;
   126→      const x = task.startDay * pxPerDay + width / 2 + CARD_PADDING;
   127→      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   128→      // Z ordering: selected > conflict > hovered > normal
   129→      const isSelected = task.id === selectedTaskId;
   130→      const isHovered = task.id === hoveredTaskId;
   131→      const z = isSelected ? 0.15 : task.hasConflict ? 0.1 : isHovered ? 0.05 : 0;
   132→
   133→      tempObject.position.set(x, y, z);
   134→      tempObject.scale.set(width, height, 1);
   135→      tempObject.updateMatrix();
   136→      mesh.setMatrixAt(i, tempObject.matrix);
   137→
   138→      // Set color: selected gets distinct color, hovered gets brightened, normal is base
   139→      if (isSelected) {
   140→        tempColor.set(SELECTION_COLOR);
   141→        mesh.setColorAt(i, tempColor);
   142→      } else if (isHovered) {
   143→        const baseColor = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
   144→        const brightened = brightenColor(baseColor, HOVER_BRIGHTNESS);
   145→        mesh.setColorAt(i, brightened);
   146→      } else {
   147→        const baseColor = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
   148→        tempColor.set(baseColor);
   149→        mesh.setColorAt(i, tempColor);
   150→      }
   151→    });
   152→
   153→    mesh.instanceMatrix.needsUpdate = true;
   154→    if (mesh.instanceColor) {
   155→      mesh.instanceColor.needsUpdate = true;
   156→    }
   157→  }, [tasks, tempObject, tempColor, hoveredTaskId, selectedTaskId]);
   158→
   159→  if (tasks.length === 0) return null;
   160→
   161→  return (
   162→    <instancedMesh ref={meshRef} args={[undefined, undefined, tasks.length]}>
   163→      <planeGeometry args={[1, 1]} />
   164→      <meshBasicMaterial toneMapped={false} transparent={opacity < 1} opacity={opacity} />
   165→    </instancedMesh>
   166→  );
   167→}
   168→
   169→/**
   170→ * Conflict glow effects (behind task cards)
   171→ */
   172→function ConflictGlows({ tasks, opacity = 1 }: { tasks: TaskRender[]; opacity?: number }) {
   173→  const conflictTasks = useMemo(() => tasks.filter((t) => t.hasConflict), [tasks]);
   174→  const meshRef = useRef<InstancedMesh>(null);
   175→  const tempObject = useMemo(() => new Object3D(), []);
   176→
   177→  useEffect(() => {
   178→    if (!meshRef.current || conflictTasks.length === 0) return;
   179→
   180→    const mesh = meshRef.current;
   181→
   182→    conflictTasks.forEach((task, i) => {
   183→      const width = task.duration * pxPerDay + 4;
   184→      const height = CARD_HEIGHT + 4;
   185→      const x = task.startDay * pxPerDay + (task.duration * pxPerDay) / 2;
   186→      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   187→      const z = -0.05;
   188→
   189→      tempObject.position.set(x, y, z);
   190→      tempObject.scale.set(width, height, 1);
   191→      tempObject.updateMatrix();
   192→      mesh.setMatrixAt(i, tempObject.matrix);
   193→    });
   194→
   195→    mesh.instanceMatrix.needsUpdate = true;
   196→  }, [conflictTasks, tempObject]);
   197→
   198→  if (conflictTasks.length === 0) return null;
   199→
   200→  return (
   201→    <instancedMesh ref={meshRef} args={[undefined, undefined, conflictTasks.length]}>
   202→      <planeGeometry args={[1, 1]} />
   203→      <meshBasicMaterial color={CONFLICT_COLOR} transparent opacity={0.3 * opacity} />
   204→    </instancedMesh>
   205→  );
   206→}
   207→
   208→/**
   209→ * HTML labels for tasks - ONLY for visible tasks (lazy rendering)
   210→ * Maximum of 50 labels rendered at once for performance
   211→ */
   212→function TaskLabels({ tasks, opacity = 1 }: { tasks: TaskRender[]; opacity?: number }) {
   213→  const { camera } = useThree();
   214→  const zoom = (camera as any).zoom || 1;
   215→
   216→  // Only show labels on tasks wide enough (> 40 screen pixels)
   217→  // And limit to max 50 labels for performance
   218→  const labeledTasks = useMemo(() => {
   219→    const minWidthForLabel = 40 / zoom; // Convert screen pixels to world pixels
   220→    const filtered = tasks.filter((t) => t.duration * pxPerDay > minWidthForLabel);
   221→    // Sort by width (largest first) and take top 50
   222→    return filtered
   223→      .sort((a, b) => b.duration - a.duration)
   224→      .slice(0, 50);
   225→  }, [tasks, zoom]);
   226→
   227→  // Don't render labels during low opacity transitions (performance optimization)
   228→  if (opacity < 0.3) return null;
   229→
   230→  return (
   231→    <>
   232→      {labeledTasks.map((task) => {
   233→        const width = task.duration * pxPerDay;
   234→        const x = task.startDay * pxPerDay + width / 2;
   235→        const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   236→        const label = task.type.charAt(0).toUpperCase() + task.type.slice(1);
   237→
   238→        return (
   239→          <Html
   240→            key={task.id}
   241→            position={[x, y, 0.2]}
   242→            center
   243→            style={{ pointerEvents: 'none', opacity }}
   244→          >
   245→            <div
   246→              style={{
   247→                color: 'white',
   248→                fontSize: '10px',
   249→                fontFamily: 'system-ui, sans-serif',
   250→                fontWeight: 600,
   251→                textShadow: '0 1px 2px rgba(0,0,0,0.3)',
   252→                whiteSpace: 'nowrap',
   253→              }}
   254→            >
   255→              {label}
   256→            </div>
   257→          </Html>
   258→        );
   259→      })}
   260→    </>
   261→  );
   262→}
   263→
   264→/**
   265→ * Grid lines using InstancedMesh (OPTIMIZED - single draw call)
   266→ * Previously: ~251 individual meshes = 251 draw calls
   267→ * Now: 2 InstancedMesh = 2 draw calls
   268→ */
   269→function GridLines({
   270→  totalDays,
   271→  trainCount,
   272→  opacity = 1,
   273→  viewportBounds,
   274→}: {
   275→  totalDays: number;
   276→  trainCount: number;
   277→  opacity?: number;
   278→  viewportBounds?: ViewportBounds;
   279→}) {
   280→  const totalWidth = totalDays * pxPerDay;
   281→  const totalHeight = trainCount * pxPerTrain;
   282→
   283→  // Horizontal grid lines (train boundaries) - using InstancedMesh
   284→  const hMeshRef = useRef<InstancedMesh>(null);
   285→  const hTempObject = useMemo(() => new Object3D(), []);
   286→
   287→  // Vertical grid lines (week boundaries) - using InstancedMesh
   288→  const vMeshRef = useRef<InstancedMesh>(null);
   289→  const vTempObject = useMemo(() => new Object3D(), []);
   290→
   291→  // Calculate visible horizontal lines based on viewport
   292→  const visibleHLines = useMemo(() => {
   293→    if (!viewportBounds) {
   294→      return Array.from({ length: trainCount + 1 }, (_, i) => i);
   295→    }
   296→    const minTrainIndex = Math.max(0, Math.floor(-viewportBounds.maxY / pxPerTrain) - 1);
   297→    const maxTrainIndex = Math.min(trainCount, Math.ceil(-viewportBounds.minY / pxPerTrain) + 1);
   298→    return Array.from({ length: maxTrainIndex - minTrainIndex + 1 }, (_, i) => minTrainIndex + i);
   299→  }, [trainCount, viewportBounds]);
   300→
   301→  // Calculate visible vertical lines (weeks) based on viewport
   302→  const visibleVLines = useMemo(() => {
   303→    if (!viewportBounds) {
   304→      const lines = [];
   305→      for (let day = 0; day <= totalDays; day += 7) {
   306→        lines.push(day);
   307→      }
   308→      return lines.slice(0, 200);
   309→    }
   310→    const minDay = Math.max(0, Math.floor(viewportBounds.minX / pxPerDay / 7) * 7 - 7);
   311→    const maxDay = Math.min(totalDays, Math.ceil(viewportBounds.maxX / pxPerDay / 7) * 7 + 7);
   312→    const lines = [];
   313→    for (let day = minDay; day <= maxDay; day += 7) {
   314→      lines.push(day);
   315→    }
   316→    return lines;
   317→  }, [totalDays, viewportBounds]);
   318→
   319→  // Update horizontal lines InstancedMesh
   320→  useEffect(() => {
   321→    if (!hMeshRef.current || visibleHLines.length === 0) return;
   322→
   323→    const mesh = hMeshRef.current;
   324→    visibleHLines.forEach((trainIndex, i) => {
   325→      hTempObject.position.set(totalWidth / 2, -trainIndex * pxPerTrain, -0.05);
   326→      hTempObject.scale.set(totalWidth, 1, 1);
   327→      hTempObject.updateMatrix();
   328→      mesh.setMatrixAt(i, hTempObject.matrix);
   329→    });
   330→    mesh.instanceMatrix.needsUpdate = true;
   331→  }, [visibleHLines, totalWidth, hTempObject]);
   332→
   333→  // Update vertical lines InstancedMesh
   334→  useEffect(() => {
   335→    if (!vMeshRef.current || visibleVLines.length === 0) return;
   336→
   337→    const mesh = vMeshRef.current;
   338→    visibleVLines.forEach((day, i) => {
   339→      const isMajor = day % 30 === 0;
   340→      vTempObject.position.set(day * pxPerDay, -totalHeight / 2, -0.05);
   341→      vTempObject.scale.set(isMajor ? 1.5 : 1, totalHeight, 1);
   342→      vTempObject.updateMatrix();
   343→      mesh.setMatrixAt(i, vTempObject.matrix);
   344→      mesh.setColorAt(i, new Color(isMajor ? GRID_COLOR_MAJOR : GRID_COLOR_MINOR));
   345→    });
   346→    mesh.instanceMatrix.needsUpdate = true;
   347→    if (mesh.instanceColor) {
   348→      mesh.instanceColor.needsUpdate = true;
   349→    }
   350→  }, [visibleVLines, totalHeight, vTempObject]);
   351→
   352→  return (
   353→    <group>
   354→      {/* Horizontal lines - InstancedMesh */}
   355→      {visibleHLines.length > 0 && (
   356→        <instancedMesh ref={hMeshRef} args={[undefined, undefined, visibleHLines.length]}>
   357→          <planeGeometry args={[1, 1]} />
   358→          <meshBasicMaterial color={GRID_COLOR_MAJOR} transparent opacity={0.5 * opacity} />
   359→        </instancedMesh>
   360→      )}
   361→
   362→      {/* Vertical lines - InstancedMesh */}
   363→      {visibleVLines.length > 0 && (
   364→        <instancedMesh ref={vMeshRef} args={[undefined, undefined, visibleVLines.length]}>
   365→          <planeGeometry args={[1, 1]} />
   366→          <meshBasicMaterial transparent opacity={0.4 * opacity} />
   367→        </instancedMesh>
   368→      )}
   369→    </group>
   370→  );
   371→}
   372→
   373→/**
   374→ * Row backgrounds using InstancedMesh (OPTIMIZED - single draw call)
   375→ * Previously: 50 individual meshes = 50 draw calls
   376→ * Now: 1 InstancedMesh = 1 draw call
   377→ */
   378→function RowBackgrounds({
   379→  trainCount,
   380→  totalDays,
   381→  opacity = 1,
   382→  viewportBounds,
   383→}: {
   384→  trainCount: number;
   385→  totalDays: number;
   386→  opacity?: number;
   387→  viewportBounds?: ViewportBounds;
   388→}) {
   389→  const totalWidth = totalDays * pxPerDay;
   390→  const meshRef = useRef<InstancedMesh>(null);
   391→  const tempObject = useMemo(() => new Object3D(), []);
   392→
   393→  // Calculate visible rows based on viewport
   394→  const visibleRows = useMemo(() => {
   395→    if (!viewportBounds) {
   396→      return Array.from({ length: trainCount }, (_, i) => i);
   397→    }
   398→    const minTrainIndex = Math.max(0, Math.floor(-viewportBounds.maxY / pxPerTrain) - 1);
   399→    const maxTrainIndex = Math.min(trainCount - 1, Math.ceil(-viewportBounds.minY / pxPerTrain) + 1);
   400→    return Array.from({ length: maxTrainIndex - minTrainIndex + 1 }, (_, i) => minTrainIndex + i);
   401→  }, [trainCount, viewportBounds]);
   402→
   403→  useEffect(() => {
   404→    if (!meshRef.current || visibleRows.length === 0) return;
   405→
   406→    const mesh = meshRef.current;
   407→    visibleRows.forEach((trainIndex, i) => {
   408→      tempObject.position.set(totalWidth / 2, -trainIndex * pxPerTrain - pxPerTrain / 2, -0.1);
   409→      tempObject.scale.set(totalWidth, pxPerTrain, 1);
   410→      tempObject.updateMatrix();
   411→      mesh.setMatrixAt(i, tempObject.matrix);
   412→      mesh.setColorAt(i, new Color(trainIndex % 2 === 0 ? ROW_BG_EVEN : ROW_BG_ODD));
   413→    });
   414→    mesh.instanceMatrix.needsUpdate = true;
   415→    if (mesh.instanceColor) {
   416→      mesh.instanceColor.needsUpdate = true;
   417→    }
   418→  }, [visibleRows, totalWidth, tempObject]);
   419→
   420→  if (visibleRows.length === 0) return null;
   421→
   422→  return (
   423→    <instancedMesh ref={meshRef} args={[undefined, undefined, visibleRows.length]}>
   424→      <planeGeometry args={[1, 1]} />
   425→      <meshBasicMaterial transparent opacity={0.5 * opacity} />
   426→    </instancedMesh>
   427→  );
   428→}
   429→
   430→/**
   431→ * MicroLayer Component
   432→ *
   433→ * Optimized for performance with:
   434→ * - Frustum culling for tasks
   435→ * - InstancedMesh for grid lines and row backgrounds
   436→ * - Limited HTML labels (max 50)
   437→ */
   438→export function MicroLayer({
   439→  tasks,
   440→  trainCount,
   441→  opacity = 1,
   442→  viewportBounds,
   443→  hoveredTaskId,
   444→  selectedTaskId,
   445→}: MicroLayerProps) {
   446→  // Calculate total days
   447→  const totalDays = useMemo(() => {
   448→    if (tasks.length === 0) return 365 * 10;
   449→    const maxDay = Math.max(...tasks.map((t) => t.startDay + t.duration));
   450→    return Math.max(maxDay + 30, 365 * 10);
   451→  }, [tasks]);
   452→
   453→  // Filter to visible tasks only (frustum culling)
   454→  const visibleTasks = useMemo(
   455→    () => filterVisibleTasks(tasks, viewportBounds),
   456→    [tasks, viewportBounds]
   457→  );
   458→
   459→  return (
   460→    <group>
   461→      {/* Row backgrounds - InstancedMesh */}
   462→      <RowBackgrounds
   463→        trainCount={trainCount}
   464→        totalDays={totalDays}
   465→        opacity={opacity}
   466→        viewportBounds={viewportBounds}
   467→      />
   468→
   469→      {/* Grid lines - InstancedMesh */}
   470→      <GridLines
   471→        totalDays={totalDays}
   472→        trainCount={trainCount}
   473→        opacity={opacity}
   474→        viewportBounds={viewportBounds}
   475→      />
   476→
   477→      {/* Conflict glow effects - only visible tasks */}
   478→      <ConflictGlows tasks={visibleTasks} opacity={opacity} />
   479→
   480→      {/* Task cards - only visible tasks */}
   481→      <TaskCards tasks={visibleTasks} opacity={opacity} hoveredTaskId={hoveredTaskId} selectedTaskId={selectedTaskId} />
   482→
   483→      {/* Task labels (HTML overlay) - only visible tasks, max 50 */}
   484→      <TaskLabels tasks={visibleTasks} opacity={opacity} />
   485→    </group>
   486→  );
   487→}
   488→

