     1→/**
     2→ * MMS Data Types
     3→ *
     4→ * Architecture: Persistence vs Rendering
     5→ *
     6→ * Data flows through two distinct layers:
     7→ *
     8→ * Persistent (JSON/API) → Runtime (in memory) → Rendering (canvas)
     9→ *   startDate: string      (Date objects)       startDay: 74
    10→ *   "2024-03-15"           for logic            trainIndex: 5
    11→ *
    12→ * Why this separation?
    13→ * - Date objects cannot be serialized to JSON (become {})
    14→ * - Canvas needs numeric offsets for position calculations
    15→ * - Domain logic needs semantic dates for business rules
    16→ */
    17→
    18→// ─────────────────────────────────────────────────────────────
    19→// ENUMS & CONSTANTS
    20→// ─────────────────────────────────────────────────────────────
    21→
    22→export type AssetType = 'ALSTOM' | 'KINKI';
    23→export type TaskType = 'maintenance' | 'overhaul' | 'inspection';
    24→export type MaintenanceLevel = 'A' | 'B' | 'C' | 'D';
    25→
    26→// ─────────────────────────────────────────────────────────────
    27→// DOMAIN TYPES (Persistent/Serializable)
    28→// These types can be saved to JSON, sent via API, or stored in localStorage.
    29→// ─────────────────────────────────────────────────────────────
    30→
    31→export interface Train {
    32→  id: string;              // "TRAIN-001" or "ALT-001"
    33→  name: string;            // Display name
    34→  assetType: AssetType;    // Fleet type
    35→}
    36→
    37→export interface Task {
    38→  id: string;              // Unique identifier
    39→  trainId: string;         // Reference to Train.id
    40→  startDate: string;       // ISO 8601 date: "2024-03-15"
    41→  endDate: string;         // ISO 8601 date: "2024-03-20"
    42→  type: TaskType;          // Visual category
    43→  hasConflict: boolean;    // Conflict indicator
    44→}
    45→
    46→export interface DatasetMeta {
    47→  startDate: string;       // ISO 8601: "2024-01-01"
    48→  trainCount: number;      // Number of trains
    49→  years: number;           // Time range in years
    50→}
    51→
    52→export interface GeneratedData {
    53→  trains: Train[];
    54→  tasks: Task[];
    55→  meta: DatasetMeta;
    56→}
    57→
    58→// ─────────────────────────────────────────────────────────────
    59→// RENDERING TYPES (Runtime/Calculated)
    60→// These types are computed when data loads and used by the canvas.
    61→// Never persisted.
    62→// ─────────────────────────────────────────────────────────────
    63→
    64→export type TaskColor = 'blue' | 'orange' | 'gray';
    65→
    66→export interface TaskRender {
    67→  id: string;              // Same as Task.id
    68→  trainIndex: number;      // Y position (0-based index in trains array)
    69→  startDay: number;        // X position (days since meta.startDate)
    70→  duration: number;        // Width (days)
    71→  color: TaskColor;        // Derived from Task.type
    72→  hasConflict: boolean;    // Passthrough from Task
    73→  type: TaskType;          // For label display in MicroLayer
    74→}
    75→
    76→export const TYPE_TO_COLOR: Record<TaskType, TaskColor> = {
    77→  maintenance: 'blue',
    78→  overhaul: 'orange',
    79→  inspection: 'gray',
    80→};
    81→
    82→// ─────────────────────────────────────────────────────────────
    83→// WORLD BOUNDS (Navigation limits)
    84→// ─────────────────────────────────────────────────────────────
    85→
    86→/**
    87→ * Defines the navigable world boundaries.
    88→ * Camera will be clamped to these bounds.
    89→ *
    90→ * Coordinate system:
    91→ * - X: 0 = first day, positive = future
    92→ * - Y: 0 = top (TRAIN-001), negative = down (more trains)
    93→ */
    94→export interface WorldBounds {
    95→  minX: number;  // 0 (first day)
    96→  maxX: number;  // totalDays * pxPerDay
    97→  minY: number;  // -trainCount * pxPerTrain (bottom)
    98→  maxY: number;  // 0 (top)
    99→}
   100→
   101→// ─────────────────────────────────────────────────────────────
   102→// CANVAS CONFIGURATION
   103→// ─────────────────────────────────────────────────────────────
   104→
   105→export interface ViewConfig {
   106→  pxPerDay: number;        // Pixels per day (X scale)
   107→  pxPerTrain: number;      // Pixels per train row (Y scale)
   108→  minZoom: number;         // Minimum zoom level
   109→  maxZoom: number;         // Maximum zoom level
   110→  zoomSensitivity: number; // Scroll sensitivity
   111→  lodThresholds: {
   112→    macro: number;         // Below this → MACRO view
   113→    micro: number;         // Above this → MICRO view
   114→  };
   115→}
   116→
   117→export type LODLevel = 'MACRO' | 'MESO' | 'MICRO';
   118→
   119→export interface ViewportState {
   120→  zoom: number;
   121→  panX: number;
   122→  panY: number;
   123→  lod: LODLevel;
   124→}
   125→
   126→// ─────────────────────────────────────────────────────────────
   127→// DEFAULT VALUES
   128→// ─────────────────────────────────────────────────────────────
   129→
   130→export const DEFAULT_VIEW_CONFIG: ViewConfig = {
   131→  pxPerDay: 10,
   132→  pxPerTrain: 24,
   133→  minZoom: 0.1,
   134→  maxZoom: 5,
   135→  zoomSensitivity: 0.002,
   136→  lodThresholds: {
   137→    macro: 0.5,
   138→    micro: 2.0,
   139→  },
   140→};
   141→
   142→export const DEFAULT_DATASET_META: DatasetMeta = {
   143→  startDate: '2024-01-01',
   144→  trainCount: 50,
   145→  years: 10,
   146→};
   147→
   148→/**
   149→ * Calculate world bounds from dataset metadata
   150→ */
   151→export function calculateWorldBounds(
   152→  trainCount: number,
   153→  totalDays: number,
   154→  config: ViewConfig = DEFAULT_VIEW_CONFIG
   155→): WorldBounds {
   156→  return {
   157→    minX: 0,
   158→    maxX: totalDays * config.pxPerDay,
   159→    minY: -trainCount * config.pxPerTrain,
   160→    maxY: 0,
   161→  };
   162→}
   163→
   164→/**
   165→ * Data bounds with padding for visualization
   166→ */
   167→export interface DataBounds {
   168→  minX: number;
   169→  maxX: number;
   170→  minY: number;
   171→  maxY: number;
   172→  width: number;
   173→  height: number;
   174→  centerX: number;
   175→  centerY: number;
   176→}
   177→
   178→/**
   179→ * Calculate actual data bounds from tasks (not theoretical world bounds)
   180→ * This is used to fit the initial view to the actual data range.
   181→ *
   182→ * @param tasks - Array of rendered tasks with position data
   183→ * @param trainCount - Total number of trains
   184→ * @param config - View configuration
   185→ * @param padding - Padding in pixels around the data bounds
   186→ */
   187→export function calculateDataBounds(
   188→  tasks: TaskRender[],
   189→  trainCount: number,
   190→  config: ViewConfig = DEFAULT_VIEW_CONFIG,
   191→  padding: number = 50
   192→): DataBounds {
   193→  if (tasks.length === 0) {
   194→    // No tasks, return default bounds
   195→    return {
   196→      minX: 0,
   197→      maxX: config.pxPerDay * 365,
   198→      minY: -trainCount * config.pxPerTrain,
   199→      maxY: 0,
   200→      width: config.pxPerDay * 365,
   201→      height: trainCount * config.pxPerTrain,
   202→      centerX: (config.pxPerDay * 365) / 2,
   203→      centerY: (-trainCount * config.pxPerTrain) / 2,
   204→    };
   205→  }
   206→
   207→  // Find min/max from actual task positions
   208→  let minStartDay = Infinity;
   209→  let maxEndDay = -Infinity;
   210→  let minTrainIndex = Infinity;
   211→  let maxTrainIndex = -Infinity;
   212→
   213→  for (const task of tasks) {
   214→    minStartDay = Math.min(minStartDay, task.startDay);
   215→    maxEndDay = Math.max(maxEndDay, task.startDay + task.duration);
   216→    minTrainIndex = Math.min(minTrainIndex, task.trainIndex);
   217→    maxTrainIndex = Math.max(maxTrainIndex, task.trainIndex);
   218→  }
   219→
   220→  // Convert to pixel coordinates
   221→  const minX = minStartDay * config.pxPerDay - padding;
   222→  const maxX = maxEndDay * config.pxPerDay + padding;
   223→  // Y is negative (trains go downward)
   224→  const maxY = -minTrainIndex * config.pxPerTrain + padding;
   225→  const minY = -(maxTrainIndex + 1) * config.pxPerTrain - padding;
   226→
   227→  const width = maxX - minX;
   228→  const height = maxY - minY;
   229→
   230→  return {
   231→    minX,
   232→    maxX,
   233→    minY,
   234→    maxY,
   235→    width,
   236→    height,
   237→    centerX: minX + width / 2,
   238→    centerY: minY + height / 2,
   239→  };
   240→}
   241→
   242→/**
   243→ * Calculate initial camera position and zoom to fit data bounds in viewport
   244→ *
   245→ * Follows the pattern used by D3.js fitExtent, Gantt chart zoomToFit, and pixi-viewport fitWorld
   246→ *
   247→ * Strategy:
   248→ * - If data fits comfortably at reasonable zoom (0.5x - 1.5x), fit all data
   249→ * - If data is too large (would require < 0.5x zoom), show starting portion at 0.5x zoom
   250→ * - This provides a good initial UX while allowing users to zoom out for full overview
   251→ *
   252→ * @param dataBounds - The data bounds to fit
   253→ * @param viewportWidth - Viewport width in pixels
   254→ * @param viewportHeight - Viewport height in pixels
   255→ * @param maxZoom - Maximum zoom level (for performance/UX)
   256→ * @param minZoom - Minimum zoom level for initial view
   257→ */
   258→export function calculateFitToView(
   259→  dataBounds: DataBounds,
   260→  viewportWidth: number,
   261→  viewportHeight: number,
   262→  maxZoom: number = 1.5,
   263→  minZoom: number = 0.5
   264→): { cameraX: number; cameraY: number; zoom: number } {
   265→  // Calculate zoom needed to fit all data in viewport
   266→  const zoomX = viewportWidth / dataBounds.width;
   267→  const zoomY = viewportHeight / dataBounds.height;
   268→  const fitAllZoom = Math.min(zoomX, zoomY);
   269→
   270→  // Clamp zoom to reasonable initial range
   271→  const zoom = Math.max(minZoom, Math.min(maxZoom, fitAllZoom));
   272→
   273→  // If we can fit all data at the calculated zoom, center on data
   274→  if (fitAllZoom >= minZoom) {
   275→    return {
   276→      cameraX: dataBounds.centerX,
   277→      cameraY: dataBounds.centerY,
   278→      zoom,
   279→    };
   280→  }
   281→
   282→  // Data is too large - show starting portion (top-left of data bounds)
   283→  // Calculate camera position to show left edge and top of data
   284→  const halfViewX = viewportWidth / 2 / zoom;
   285→  const halfViewY = viewportHeight / 2 / zoom;
   286→
   287→  return {
   288→    cameraX: dataBounds.minX + halfViewX,
   289→    cameraY: dataBounds.maxY - halfViewY, // maxY is the top (less negative)
   290→    zoom,
   291→  };
   292→}
   293→
   294→// ─────────────────────────────────────────────────────────────
   295→// FUTURE EXTENSIONS (Optional Fields)
   296→// These fields can be added without breaking existing code.
   297→// ─────────────────────────────────────────────────────────────
