/**
 * Generate tasks for all trains
 */
function generateTasks(trains: Train[], meta: DatasetMeta): Task[] {
  const tasks: Task[] = [];
  const types: TaskType[] = ['maintenance', 'overhaul', 'inspection'];

  trains.forEach((train, trainIndex) => {
    for (let year = 0; year < meta.years; year++) {
      // 8-12 tasks per year per train
      const tasksPerYear = 8 + Math.floor(Math.random() * 5);

      for (let t = 0; t < tasksPerYear; t++) {
        // First task of year 0 for each train starts early (within first 60 days)
        // This ensures data is visible at initial camera position
        let dayOffset: number;
        if (year === 0 && t === 0) {
          dayOffset = trainIndex * 3 + Math.floor(Math.random() * 30);
        } else {
          dayOffset = year * 365 + Math.floor(Math.random() * 360);
        }
        const duration = 2 + Math.floor(Math.random() * 10);
        const startDate = addDays(meta.startDate, dayOffset);
        const endDate = addDays(startDate, duration);

        tasks.push({
          id: `${train.id}-${year}-${t}`,
          trainId: train.id,
          startDate: formatISO(startDate),
          endDate: formatISO(endDate),
          type: types[Math.floor(Math.random() * types.length)],
          hasConflict: Math.random() < 0.05, // 5% conflict rate
        });
      }
    }
  });

  // Add dependencies between tasks (F023)
  // ~10-15% of tasks will have a predecessor
  // Dependencies can be within the same train or across different trains
  addDependencies(tasks, meta);

  return tasks;
}

/**
 * Add dependency relationships between tasks (F023)
 *
 * Strategy:
 * - ~10-15% of tasks get a predecessor
 * - Predecessor must end before the current task starts (valid dependency)
 * - Mix of same-train and cross-train dependencies
 * - Overhauls often depend on inspections (realistic pattern)
 */
function addDependencies(tasks: Task[], meta: DatasetMeta): void {
  // Build a lookup by start date for efficient predecessor search
  const sortedTasks = [...tasks].sort(
    (a, b) => new Date(a.startDate).getTime() - new Date(b.startDate).getTime()
  );

  // Create a map for quick task lookup
  const taskMap = new Map<string, Task>(tasks.map((t) => [t.id, t]));

  // Group tasks by train for same-train dependencies
  const tasksByTrain = new Map<string, Task[]>();
  for (const task of sortedTasks) {
    const list = tasksByTrain.get(task.trainId) || [];
    list.push(task);
    tasksByTrain.set(task.trainId, list);
  }

  // Assign dependencies
  for (const task of tasks) {
    // Skip if already has conflict (to avoid visual clutter)
    if (task.hasConflict) continue;

    // ~12% chance of having a dependency
    if (Math.random() >= 0.12) continue;

    const taskStartTime = new Date(task.startDate).getTime();

    // 70% same-train dependency, 30% cross-train dependency
    const sameTrain = Math.random() < 0.7;

    let candidates: Task[];
    if (sameTrain) {
      // Find tasks on the same train that end before this one starts
      candidates = (tasksByTrain.get(task.trainId) || []).filter((t) => {
        const endTime = new Date(t.endDate).getTime();
        // Predecessor must end at least 1 day before (gap for realism)
        // and within 60 days (reasonable dependency window)
        const gap = (taskStartTime - endTime) / (1000 * 60 * 60 * 24);
        return t.id !== task.id && gap >= 1 && gap <= 60;
      });
    } else {
      // Find tasks on different trains that end before this one starts
      candidates = sortedTasks.filter((t) => {
        if (t.trainId === task.trainId || t.id === task.id) return false;
        const endTime = new Date(t.endDate).getTime();
        const gap = (taskStartTime - endTime) / (1000 * 60 * 60 * 24);
        return gap >= 1 && gap <= 30; // Tighter window for cross-train
      });
    }

    if (candidates.length > 0) {
      // Pick a random predecessor from candidates
      const predecessor = candidates[Math.floor(Math.random() * candidates.length)];
      task.predecessorId = predecessor.id;
    }
  }
}

