toolUseResult.originalFile:
/**
 * MicroLayer - Detailed task card visualization
 *
 * Renders detailed task cards with labels at zoom > 2.0x (MICRO LOD level).
 *
 * PERFORMANCE OPTIMIZATIONS:
 * - Frustum culling: Only renders tasks visible in the viewport
 * - InstancedMesh for grid lines: Single draw call instead of ~251 meshes
 * - Lazy label rendering: Only labels for visible tasks
 * - InstancedMesh for row backgrounds: Single draw call instead of 50 meshes
 */

import { useMemo, useRef, useEffect } from 'react';
import { InstancedMesh, Object3D, Color } from 'three';
import { Html } from '@react-three/drei';
import { useThree } from '@react-three/fiber';
import type { TaskRender } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';
import type { ViewportBounds } from '../InfiniteCanvas';

interface MicroLayerProps {
  tasks: TaskRender[];
  trainCount: number;
  /** Opacity for LOD transitions (0-1). Default: 1 */
  opacity?: number;
  /** Viewport bounds for frustum culling */
  viewportBounds?: ViewportBounds;
  /** Currently hovered task ID for highlight effect */
  hoveredTaskId?: string | null;
  /** Currently selected task ID for selection highlight (F019) */
  selectedTaskId?: string | null;
}

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

// Task card dimensions
const CARD_PADDING = 2;
const CARD_HEIGHT = pxPerTrain - CARD_PADDING * 2 - 2; // Slightly smaller for grid visibility

// Color mappings (matching MesoLayer)
const COLORS: Record<string, string> = {
  blue: '#3b82f6',
  orange: '#f59e0b',
  gray: '#9ca3af',
};
const CONFLICT_COLOR = '#ef4444';

// Grid colors
const GRID_COLOR_MAJOR = '#d1d5db'; // Gray-300
const GRID_COLOR_MINOR = '#e5e7eb'; // Gray-200

// Row background colors
const ROW_BG_EVEN = '#ffffff';
const ROW_BG_ODD = '#f8fafc';

/**
 * Filter tasks that are visible within the viewport bounds
 * This is the core of frustum culling for performance
 */
function filterVisibleTasks(tasks: TaskRender[], viewportBounds?: ViewportBounds): TaskRender[] {
  if (!viewportBounds) return tasks;

  // Add padding to viewport bounds (render slightly outside visible area for smooth panning)
  const padding = 100; // world units
  const minX = viewportBounds.minX - padding;
  const maxX = viewportBounds.maxX + padding;
  const minY = viewportBounds.minY - padding;
  const maxY = viewportBounds.maxY + padding;

  return tasks.filter((task) => {
    const taskStartX = task.startDay * pxPerDay;
    const taskEndX = taskStartX + task.duration * pxPerDay;
    const taskY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;

    // Check if task overlaps with viewport
    const xOverlap = taskEndX >= minX && taskStartX <= maxX;
    const yOverlap = taskY + pxPerTrain / 2 >= minY && taskY - pxPerTrain / 2 <= maxY;

    return xOverlap && yOverlap;
  });
}

// Highlight color multiplier for hovered tasks
const HOVER_BRIGHTNESS = 1.3;

// Selection indicator color (distinct cyan/teal)
const SELECTION_COLOR = '#06b6d4'; // cyan-500

/**
 * Brighten a color for hover effect
 */
function brightenColor(hexColor: string, factor: number): Color {
  const color = new Color(hexColor);
  color.r = Math.min(1, color.r * factor);
  color.g = Math.min(1, color.g * factor);
  color.b = Math.min(1, color.b * factor);
  return color;
}

/**
 * Task cards using InstancedMesh (same pattern as MesoLayer)
 */
function TaskCards({
  tasks,
  opacity = 1,
  hoveredTaskId,
  selectedTaskId,
}: {
  tasks: TaskRender[];
  opacity?: number;
  hoveredTaskId?: string | null;
  selectedTaskId?: string | null;
}) {
  const meshRef = useRef<InstancedMesh>(null);
  const tempObject = useMemo(() => new Object3D(), []);
  const tempColor = useMemo(() => new Color(), []);

  useEffect(() => {
    if (!meshRef.current || tasks.length === 0) return;

    const mesh = meshRef.current;

    tasks.forEach((task, i) => {
      const width = task.duration * pxPerDay - CARD_PADDING * 2;
      const height = CARD_HEIGHT;
      const x = task.startDay * pxPerDay + width / 2 + CARD_PADDING;
      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
      // Z ordering: selected > conflict > hovered > normal
      const isSelected = task.id === selectedTaskId;
      const isHovered = task.id === hoveredTaskId;
      const z = isSelected ? 0.15 : task.hasConflict ? 0.1 : isHovered ? 0.05 : 0;

      tempObject.position.set(x, y, z);
      tempObject.scale.set(width, height, 1);
      tempObject.updateMatrix();
      mesh.setMatrixAt(i, tempObject.matrix);

      // Set color: selected gets distinct color, hovered gets brightened, normal is base
      if (isSelected) {
        tempColor.set(SELECTION_COLOR);
        mesh.setColorAt(i, tempColor);
      } else if (isHovered) {
        const baseColor = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
        const brightened = brightenColor(baseColor, HOVER_BRIGHTNESS);
        mesh.setColorAt(i, brightened);
      } else {
        const baseColor = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
        tempColor.set(baseColor);
        mesh.setColorAt(i, tempColor);
      }
    });

    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) {
      mesh.instanceColor.needsUpdate = true;
    }
  }, [tasks, tempObject, tempColor, hoveredTaskId, selectedTaskId]);

  if (tasks.length === 0) return null;

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, tasks.length]}>
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial toneMapped={false} transparent={opacity < 1} opacity={opacity} />
    </instancedMesh>
  );
}

/**
 * Conflict glow effects (behind task cards)
 */
function ConflictGlows({ tasks, opacity = 1 }: { tasks: TaskRender[]; opacity?: number }) {
  const conflictTasks = useMemo(() => tasks.filter((t) => t.hasConflict), [tasks]);
  const meshRef = useRef<InstancedMesh>(null);
  const tempObject = useMemo(() => new Object3D(), []);

  useEffect(() => {
    if (!meshRef.current || conflictTasks.length === 0) return;

    const mesh = meshRef.current;

    conflictTasks.forEach((task, i) => {
      const width = task.duration * pxPerDay + 4;
      const height = CARD_HEIGHT + 4;
      const x = task.startDay * pxPerDay + (task.duration * pxPerDay) / 2;
      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
      const z = -0.05;

      tempObject.position.set(x, y, z);
      tempObject.scale.set(width, height, 1);
      tempObject.updateMatrix();
      mesh.setMatrixAt(i, tempObject.matrix);
    });

    mesh.instanceMatrix.needsUpdate = true;
  }, [conflictTasks, tempObject]);

  if (conflictTasks.length === 0) return null;

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, conflictTasks.length]}>
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial color={CONFLICT_COLOR} transparent opacity={0.3 * opacity} />
    </instancedMesh>
  );
}

/**
 * HTML labels for tasks - ONLY for visible tasks (lazy rendering)
 * Maximum of 50 labels rendered at once for performance
 */
function TaskLabels({ tasks, opacity = 1 }: { tasks: TaskRender[]; opacity?: number }) {
  const { camera } = useThree();
  const zoom = (camera as any).zoom || 1;

  // Only show labels on tasks wide enough (> 40 screen pixels)
  // And limit to max 50 labels for performance
  const labeledTasks = useMemo(() => {
    const minWidthForLabel = 40 / zoom; // Convert screen pixels to world pixels
    const filtered = tasks.filter((t) => t.duration * pxPerDay > minWidthForLabel);
    // Sort by width (largest first) and take top 50
    return filtered
      .sort((a, b) => b.duration - a.duration)
      .slice(0, 50);
  }, [tasks, zoom]);

  // Don't render labels during low opacity transitions (performance optimization)
  if (opacity < 0.3) return null;

  return (
    <>
      {labeledTasks.map((task) => {
        const width = task.duration * pxPerDay;
        const x = task.startDay * pxPerDay + width / 2;
        const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
        const label = task.type.charAt(0).toUpperCase() + task.type.slice(1);

        return (
          <Html
            key={task.id}
            position={[x, y, 0.2]}
            center
            style={{ pointerEvents: 'none', opacity }}
          >
            <div
              style={{
                color: 'white',
                fontSize: '10px',
                fontFamily: 'system-ui, sans-serif',
                fontWeight: 600,
                textShadow: '0 1px 2px rgba(0,0,0,0.3)',
                whiteSpace: 'nowrap',
              }}
            >
              {label}
            </div>
          </Html>
        );
      })}
    </>
  );
}

/**
 * Grid lines using InstancedMesh (OPTIMIZED - single draw call)
 * Previously: ~251 individual meshes = 251 draw calls
 * Now: 2 InstancedMesh = 2 draw calls
 */
function GridLines({
  totalDays,
  trainCount,
  opacity = 1,
  viewportBounds,
}: {
  totalDays: number;
  trainCount: number;
  opacity?: number;
  viewportBounds?: ViewportBounds;
}) {
  const totalWidth = totalDays * pxPerDay;
  const totalHeight = trainCount * pxPerTrain;

  // Horizontal grid lines (train boundaries) - using InstancedMesh
  const hMeshRef = useRef<InstancedMesh>(null);
  const hTempObject = useMemo(() => new Object3D(), []);

  // Vertical grid lines (week boundaries) - using InstancedMesh
  const vMeshRef = useRef<InstancedMesh>(null);
  const vTempObject = useMemo(() => new Object3D(), []);

  // Calculate visible horizontal lines based on viewport
  const visibleHLines = useMemo(() => {
    if (!viewportBounds) {
      return Array.from({ length: trainCount + 1 }, (_, i) => i);
    }
    const minTrainIndex = Math.max(0, Math.floor(-viewportBounds.maxY / pxPerTrain) - 1);
    const maxTrainIndex = Math.min(trainCount, Math.ceil(-viewportBounds.minY / pxPerTrain) + 1);
    return Array.from({ length: maxTrainIndex - minTrainIndex + 1 }, (_, i) => minTrainIndex + i);
  }, [trainCount, viewportBounds]);

  // Calculate visible vertical lines (weeks) based on viewport
  const visibleVLines = useMemo(() => {
    if (!viewportBounds) {
      const lines = [];
      for (let day = 0; day <= totalDays; day += 7) {
        lines.push(day);
      }
      return lines.slice(0, 200);
    }
    const minDay = Math.max(0, Math.floor(viewportBounds.minX / pxPerDay / 7) * 7 - 7);
    const maxDay = Math.min(totalDays, Math.ceil(viewportBounds.maxX / pxPerDay / 7) * 7 + 7);
    const lines = [];
    for (let day = minDay; day <= maxDay; day += 7) {
      lines.push(day);
    }
    return lines;
  }, [totalDays, viewportBounds]);

  // Update horizontal lines InstancedMesh
  useEffect(() => {
    if (!hMeshRef.current || visibleHLines.length === 0) return;

    const mesh = hMeshRef.current;
    visibleHLines.forEach((trainIndex, i) => {
      hTempObject.position.set(totalWidth / 2, -trainIndex * pxPerTrain, -0.05);
      hTempObject.scale.set(totalWidth, 1, 1);
      hTempObject.updateMatrix();
      mesh.setMatrixAt(i, hTempObject.matrix);
    });
    mesh.instanceMatrix.needsUpdate = true;
  }, [visibleHLines, totalWidth, hTempObject]);

  // Update vertical lines InstancedMesh
  useEffect(() => {
    if (!vMeshRef.current || visibleVLines.length === 0) return;

    const mesh = vMeshRef.current;
    visibleVLines.forEach((day, i) => {
      const isMajor = day % 30 === 0;
      vTempObject.position.set(day * pxPerDay, -totalHeight / 2, -0.05);
      vTempObject.scale.set(isMajor ? 1.5 : 1, totalHeight, 1);
      vTempObject.updateMatrix();
      mesh.setMatrixAt(i, vTempObject.matrix);
      mesh.setColorAt(i, new Color(isMajor ? GRID_COLOR_MAJOR : GRID_COLOR_MINOR));
    });
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) {
      mesh.instanceColor.needsUpdate = true;
    }
  }, [visibleVLines, totalHeight, vTempObject]);

  return (
    <group>
      {/* Horizontal lines - InstancedMesh */}
      {visibleHLines.length > 0 && (
        <instancedMesh ref={hMeshRef} args={[undefined, undefined, visibleHLines.length]}>
          <planeGeometry args={[1, 1]} />
          <meshBasicMaterial color={GRID_COLOR_MAJOR} transparent opacity={0.5 * opacity} />
        </instancedMesh>
      )}

      {/* Vertical lines - InstancedMesh */}
      {visibleVLines.length > 0 && (
        <instancedMesh ref={vMeshRef} args={[undefined, undefined, visibleVLines.length]}>
          <planeGeometry args={[1, 1]} />
          <meshBasicMaterial transparent opacity={0.4 * opacity} />
        </instancedMesh>
      )}
    </group>
  );
}

/**
 * Row backgrounds using InstancedMesh (OPTIMIZED - single draw call)
 * Previously: 50 individual meshes = 50 draw calls
 * Now: 1 InstancedMesh = 1 draw call
 */
function RowBackgrounds({
  trainCount,
  totalDays,
  opacity = 1,
  viewportBounds,
}: {
  trainCount: number;
  totalDays: number;
  opacity?: number;
  viewportBounds?: ViewportBounds;
}) {
  const totalWidth = totalDays * pxPerDay;
  const meshRef = useRef<InstancedMesh>(null);
  const tempObject = useMemo(() => new Object3D(), []);

  // Calculate visible rows based on viewport
  const visibleRows = useMemo(() => {
    if (!viewportBounds) {
      return Array.from({ length: trainCount }, (_, i) => i);
    }
    const minTrainIndex = Math.max(0, Math.floor(-viewportBounds.maxY / pxPerTrain) - 1);
    const maxTrainIndex = Math.min(trainCount - 1, Math.ceil(-viewportBounds.minY / pxPerTrain) + 1);
    return Array.from({ length: maxTrainIndex - minTrainIndex + 1 }, (_, i) => minTrainIndex + i);
  }, [trainCount, viewportBounds]);

  useEffect(() => {
    if (!meshRef.current || visibleRows.length === 0) return;

    const mesh = meshRef.current;
    visibleRows.forEach((trainIndex, i) => {
      tempObject.position.set(totalWidth / 2, -trainIndex * pxPerTrain - pxPerTrain / 2, -0.1);
      tempObject.scale.set(totalWidth, pxPerTrain, 1);
      tempObject.updateMatrix();
      mesh.setMatrixAt(i, tempObject.matrix);
      mesh.setColorAt(i, new Color(trainIndex % 2 === 0 ? ROW_BG_EVEN : ROW_BG_ODD));
    });
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) {
      mesh.instanceColor.needsUpdate = true;
    }
  }, [visibleRows, totalWidth, tempObject]);

  if (visibleRows.length === 0) return null;

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, visibleRows.length]}>
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial transparent opacity={0.5 * opacity} />
    </instancedMesh>
  );
}

/**
 * MicroLayer Component
 *
 * Optimized for performance with:
 * - Frustum culling for tasks
 * - InstancedMesh for grid lines and row backgrounds
 * - Limited HTML labels (max 50)
 */
export function MicroLayer({
  tasks,
  trainCount,
  opacity = 1,
  viewportBounds,
  hoveredTaskId,
  selectedTaskId,
}: MicroLayerProps) {
  // Calculate total days
  const totalDays = useMemo(() => {
    if (tasks.length === 0) return 365 * 10;
    const maxDay = Math.max(...tasks.map((t) => t.startDay + t.duration));
    return Math.max(maxDay + 30, 365 * 10);
  }, [tasks]);

  // Filter to visible tasks only (frustum culling)
  const visibleTasks = useMemo(
    () => filterVisibleTasks(tasks, viewportBounds),
    [tasks, viewportBounds]
  );

  return (
    <group>
      {/* Row backgrounds - InstancedMesh */}
      <RowBackgrounds
        trainCount={trainCount}
        totalDays={totalDays}
        opacity={opacity}
        viewportBounds={viewportBounds}
      />

      {/* Grid lines - InstancedMesh */}
      <GridLines
        totalDays={totalDays}
        trainCount={trainCount}
        opacity={opacity}
        viewportBounds={viewportBounds}
      />

      {/* Conflict glow effects - only visible tasks */}
      <ConflictGlows tasks={visibleTasks} opacity={opacity} />

      {/* Task cards - only visible tasks */}
      <TaskCards tasks={visibleTasks} opacity={opacity} hoveredTaskId={hoveredTaskId} selectedTaskId={selectedTaskId} />

      {/* Task labels (HTML overlay) - only visible tasks, max 50 */}
      <TaskLabels tasks={visibleTasks} opacity={opacity} />
    </group>
  );
}

