// Dependency line color
const DEPENDENCY_LINE_COLOR = '#8b5cf6'; // Purple-500 for visibility
const DEPENDENCY_ARROW_COLOR = '#7c3aed'; // Purple-600 for arrow heads

/**
 * Dependency Lines between tasks (F023)
 *
 * Renders curved lines from predecessor task to dependent task with arrow heads.
 * Only renders dependencies where both tasks are in the visible set.
 */
function DependencyLines({
  tasks,
  opacity = 1,
  viewportBounds,
}: {
  tasks: TaskRender[];
  opacity?: number;
  viewportBounds?: ViewportBounds;
}) {
  // Build a map of task ID to task for quick lookup
  const taskMap = useMemo(() => {
    return new Map(tasks.map((t) => [t.id, t]));
  }, [tasks]);

  // Find dependencies where both predecessor and dependent are visible
  const dependencies = useMemo(() => {
    const deps: Array<{ from: TaskRender; to: TaskRender }> = [];

    for (const task of tasks) {
      if (task.predecessorId) {
        const predecessor = taskMap.get(task.predecessorId);
        if (predecessor) {
          deps.push({ from: predecessor, to: task });
        }
      }
    }

    return deps;
  }, [tasks, taskMap]);

  // Don't render during low opacity transitions (performance)
  if (opacity < 0.3 || dependencies.length === 0) return null;

  return (
    <group>
      {dependencies.map(({ from, to }, index) => {
        // Calculate connection points
        // From: right edge of predecessor task (end)
        const fromX = (from.startDay + from.duration) * pxPerDay;
        const fromY = -from.trainIndex * pxPerTrain - pxPerTrain / 2;

        // To: left edge of dependent task (start)
        const toX = to.startDay * pxPerDay;
        const toY = -to.trainIndex * pxPerTrain - pxPerTrain / 2;

        // Create curved path using bezier-like points
        const isSameRow = from.trainIndex === to.trainIndex;
        const midX = (fromX + toX) / 2;

        // Control points for curve
        let points: Vector3[];
        if (isSameRow) {
          // Same row: simple horizontal line with slight vertical offset to avoid overlap
          const offsetY = 8;
          points = [
            new Vector3(fromX, fromY + offsetY, 0.3),
            new Vector3(midX, fromY + offsetY + 5, 0.3),
            new Vector3(toX, toY + offsetY, 0.3),
          ];
        } else {
          // Different rows: curved path
          const controlOffset = Math.abs(toY - fromY) * 0.3;
          points = [
            new Vector3(fromX, fromY, 0.3),
            new Vector3(fromX + controlOffset, fromY, 0.3),
            new Vector3(midX, (fromY + toY) / 2, 0.3),
            new Vector3(toX - controlOffset, toY, 0.3),
            new Vector3(toX, toY, 0.3),
          ];
        }

        // Arrow head points (triangle at the destination)
        const arrowSize = 6;
        const lastPoint = points[points.length - 1];
        const secondLastPoint = points[points.length - 2];

        // Direction vector for arrow
        const direction = new Vector3().subVectors(lastPoint, secondLastPoint).normalize();
        const perpendicular = new Vector3(-direction.y, direction.x, 0);

        const arrowTip = lastPoint.clone();
        const arrowBase1 = lastPoint.clone().sub(direction.clone().multiplyScalar(arrowSize)).add(perpendicular.clone().multiplyScalar(arrowSize / 2));
        const arrowBase2 = lastPoint.clone().sub(direction.clone().multiplyScalar(arrowSize)).sub(perpendicular.clone().multiplyScalar(arrowSize / 2));

        const arrowPoints = [
          arrowTip,
          arrowBase1,
          arrowBase2,
          arrowTip, // Close the triangle
        ];

        const key = `dep-${from.id}-${to.id}`;

        return (
          <group key={key}>
            {/* Main dependency line */}
            <Line
              points={points}
              color={DEPENDENCY_LINE_COLOR}
              lineWidth={2}
              opacity={opacity * 0.8}
              transparent
            />
            {/* Arrow head */}
            <Line
              points={arrowPoints}
              color={DEPENDENCY_ARROW_COLOR}
              lineWidth={2}
              opacity={opacity}
              transparent
            />
          </group>
        );
      })}
    </group>
  );
}

